import React from 'react';

export default function Contact() {
  return (
    <div>
      {/* ── MAIN ── */}
      <section style={{
        minHeight: '80vh', display: 'flex', alignItems: 'center',
        position: 'relative', overflow: 'hidden', paddingTop: '100px',
      }}>
        <div style={{
          position: 'absolute', inset: 0,
          background: 'linear-gradient(135deg, #0c0800 0%, #1a0e00 60%, #0c0800 100%)',
        }} />
        <div style={{
          position: 'absolute', top: '20%', right: '8%',
          width: '400px', height: '400px',
          background: 'radial-gradient(circle, rgba(245,158,11,0.16) 0%, transparent 70%)',
        }} />
        <div style={{
          position: 'absolute', bottom: '15%', left: '3%',
          width: '320px', height: '320px',
          background: 'radial-gradient(circle, rgba(234,108,30,0.12) 0%, transparent 70%)',
        }} />

        <div className="container" style={{ position: 'relative', zIndex: 1 }}>
          <div style={{ maxWidth: '580px' }}>
            <span className="label">Contact</span>
            <h1 style={{
              fontSize: 'clamp(48px, 6.5vw, 82px)',
              fontWeight: 400, lineHeight: '1.06',
              color: 'var(--text)', marginBottom: '22px',
            }}>
              Let's{' '}
              <span style={{
                background: 'linear-gradient(135deg, #fbbf24, #f59e0b, #ea6c1e)',
                WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text',
                fontStyle: 'italic',
              }}>talk.</span>
            </h1>
            <p style={{
              fontSize: '16px', color: 'var(--text-2)',
              lineHeight: '1.72', marginBottom: '40px', maxWidth: '460px',
            }}>
              Whether you have a specific goal or just a sense that something needs to change, I look forward to hearing from you.
            </p>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '14px', alignItems: 'flex-start' }}>
              <a href="mailto:fayzanrabcoaching@gmail.com" style={{
                display: 'inline-flex', alignItems: 'center', gap: '10px',
                padding: '14px 28px', borderRadius: '100px',
                background: 'linear-gradient(135deg, #f59e0b, #ea6c1e)',
                color: '#fff', fontSize: '15px', fontWeight: 600,
                textDecoration: 'none',
                boxShadow: '0 0 32px rgba(245,158,11,0.32)',
                transition: 'all 0.22s ease',
              }}
              onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-2px)'; e.currentTarget.style.boxShadow = '0 0 52px rgba(245,158,11,0.5)'; }}
              onMouseLeave={e => { e.currentTarget.style.transform = 'none'; e.currentTarget.style.boxShadow = '0 0 32px rgba(245,158,11,0.32)'; }}
              >
                <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/>
                  <polyline points="22,6 12,13 2,6"/>
                </svg>
                fayzanrabcoaching@gmail.com
              </a>

              <a href="https://linkedin.com" target="_blank" rel="noopener noreferrer" style={{
                display: 'inline-flex', alignItems: 'center', gap: '6px',
                fontSize: '12px', fontWeight: 700, letterSpacing: '0.1em',
                textTransform: 'uppercase', color: 'var(--text-3)',
                textDecoration: 'none', transition: 'color 0.2s ease',
              }}
              onMouseEnter={e => { e.currentTarget.style.color = 'var(--amber)'; }}
              onMouseLeave={e => { e.currentTarget.style.color = 'var(--text-3)'; }}
              >LinkedIn →</a>
            </div>
          </div>
        </div>
      </section>

      {/* ── TESTIMONIAL ── */}
      <section style={{
        padding: '80px 28px 96px',
        background: 'linear-gradient(135deg, rgba(245,158,11,0.04) 0%, rgba(234,108,30,0.05) 100%)',
      }}>
        <div className="container" style={{ textAlign: 'center', maxWidth: '660px', margin: '0 auto' }}>
          <div style={{
            width: '40px', height: '2px',
            background: 'linear-gradient(90deg, #f59e0b, #ea6c1e)',
            borderRadius: '2px', margin: '0 auto 30px',
          }} />
          <p style={{
            fontSize: 'clamp(19px, 2.3vw, 28px)',
            fontFamily: "'DM Serif Display', serif",
            fontWeight: 400, lineHeight: '1.48',
            color: 'var(--text)', marginBottom: '24px',
          }}>
            "Working with Fayzan allowed me to rapidly step into the best version of myself in a way that feels genuine and lasting."
          </p>
          <p style={{
            fontSize: '11px', fontWeight: 700, letterSpacing: '0.14em',
            textTransform: 'uppercase', color: 'var(--amber)',
          }}>— Aatash Parikh, Founder at Inkwire</p>
        </div>
      </section>
    </div>
  );
}
